/**
 * Integration tests for the MCP OAuth 2.0 server endpoints.
 *
 * Verifies the metadata documents required by Claude.ai's "Add custom
 * connector" flow, that an unauthenticated /mcp request returns 401 with
 * the proper WWW-Authenticate header, and that the legacy MCP_API_KEY
 * still works as a fallback for Claude Desktop / mcp-remote users.
 */
import supertest from 'supertest';
import { describe, it, expect, beforeAll } from '@jest/globals';

describe('MCP OAuth 2.0 endpoints', () => {
  let request: supertest.SuperTest<supertest.Test>;
  let priorApiKey: string | undefined;

  beforeAll(async () => {
    process.env.NODE_ENV = 'test';
    priorApiKey = process.env.MCP_API_KEY;
    process.env.MCP_API_KEY = priorApiKey ?? 'test-mcp-key';
    process.env.MCP_OAUTH_ISSUER =
      process.env.MCP_OAUTH_ISSUER ?? 'https://mcp.test.local';

    const { testApp } = await import('./test-app');
    request = supertest(testApp);
  });

  it('serves OAuth Authorization Server metadata', async () => {
    const res = await request.get('/.well-known/oauth-authorization-server');
    expect(res.status).toBe(200);
    expect(res.body.issuer).toMatch(/^https?:\/\//);
    expect(res.body.authorization_endpoint).toBeDefined();
    expect(res.body.token_endpoint).toBeDefined();
    expect(res.body.registration_endpoint).toBeDefined();
    expect(res.body.code_challenge_methods_supported).toContain('S256');
    expect(res.body.grant_types_supported).toEqual(
      expect.arrayContaining(['authorization_code', 'refresh_token']),
    );
  });

  it('serves OAuth Protected Resource metadata for /mcp', async () => {
    const res = await request.get('/.well-known/oauth-protected-resource/mcp');
    expect(res.status).toBe(200);
    expect(res.body.resource).toContain('/mcp');
    expect(Array.isArray(res.body.authorization_servers)).toBe(true);
    expect(res.body.resource_name).toBe('Koveo Gestion MCP');
  });

  it('rejects unauthenticated /mcp with WWW-Authenticate pointing at resource metadata', async () => {
    const res = await request
      .post('/mcp')
      .set('Accept', 'application/json, text/event-stream')
      .send({ jsonrpc: '2.0', id: 1, method: 'initialize' });
    expect(res.status).toBe(401);
    const wwwAuth = res.headers['www-authenticate'];
    expect(wwwAuth).toBeDefined();
    expect(wwwAuth).toMatch(/Bearer/);
    expect(wwwAuth).toMatch(/resource_metadata=/);
    expect(wwwAuth).toMatch(/oauth-protected-resource\/mcp/);
  });

  it('accepts the legacy MCP_API_KEY as a Bearer token (back-compat)', async () => {
    const res = await request
      .post('/mcp')
      .set('Authorization', `Bearer ${process.env.MCP_API_KEY}`)
      .set('Accept', 'application/json, text/event-stream')
      .set('Content-Type', 'application/json')
      .send({
        jsonrpc: '2.0',
        id: 1,
        method: 'initialize',
        params: {
          protocolVersion: '2024-11-05',
          capabilities: {},
          clientInfo: { name: 'jest', version: '1.0.0' },
        },
      });
    // Should NOT be 401. May be 200 (success) or 4xx for protocol issues —
    // the goal here is purely to confirm the legacy key is still honored.
    expect(res.status).not.toBe(401);
  });

  it('supports RFC 7591 Dynamic Client Registration', async () => {
    const res = await request
      .post('/register')
      .set('Content-Type', 'application/json')
      .send({
        redirect_uris: ['https://claude.ai/api/mcp/auth_callback'],
        client_name: 'Jest Test Client',
        token_endpoint_auth_method: 'client_secret_post',
      });
    expect(res.status).toBe(201);
    expect(res.body.client_id).toMatch(/^koveo-mcp-/);
    expect(res.body.client_secret).toBeDefined();
    expect(res.body.client_secret_expires_at).toBeGreaterThan(
      Math.floor(Date.now() / 1000),
    );
  });
});
